#!/bin/bash\n\n# Barcode Management System - Automated Setup Script (Linux/Mac)\n# This script will install and setup the entire application\n\necho \"═══════════════════════════════════════════════════════════\"\necho \"🚀 Barcode Management & Security Gate Entry System\"\necho \"   Automated Installation Script (Linux/Mac)\"\necho \"═══════════════════════════════════════════════════════════\"\necho \"\"\n\n# Colors for output\nRED='\\033[0;31m'\nGREEN='\\033[0;32m'\nYELLOW='\\033[1;33m'\nNC='\\033[0m' # No Color\n\n# Check if Node.js is installed\necho \"${YELLOW}[1/7] Checking Node.js installation...${NC}\"\nif ! command -v node &> /dev/null; then\n    echo \"${RED}❌ Node.js is not installed. Please install Node.js from https://nodejs.org/${NC}\"\n    exit 1\nfi\nNODE_VERSION=$(node -v)\necho \"${GREEN}✅ Node.js ${NODE_VERSION} found${NC}\"\n\n# Check if MySQL is installed\necho \"\"\necho \"${YELLOW}[2/7] Checking MySQL installation...${NC}\"\nif ! command -v mysql &> /dev/null; then\n    echo \"${RED}❌ MySQL is not installed. Please install MySQL from https://www.mysql.com/downloads/${NC}\"\n    exit 1\nfi\necho \"${GREEN}✅ MySQL found${NC}\"\n\n# Check if Git is installed\necho \"\"\necho \"${YELLOW}[3/7] Checking Git installation...${NC}\"\nif ! command -v git &> /dev/null; then\n    echo \"${RED}❌ Git is not installed. Please install Git from https://git-scm.com/${NC}\"\n    exit 1\nfi\necho \"${GREEN}✅ Git found${NC}\"\n\n# Clone repository if not already cloned\necho \"\"\necho \"${YELLOW}[4/7] Setting up repository...${NC}\"\nif [ ! -d \"barcode\" ]; then\n    echo \"Cloning repository...\"\n    git clone https://github.com/shindeshailesh962/barcode.git\n    cd barcode\nelse\n    echo \"Repository already exists, skipping clone.\"\n    cd barcode\nfi\necho \"${GREEN}✅ Repository ready${NC}\"\n\n# Setup Backend\necho \"\"\necho \"${YELLOW}[5/7] Installing Backend dependencies...${NC}\"\ncd backend\nif [ ! -f \".env\" ]; then\n    echo \"Creating .env file from template...\"\n    cp .env.example .env\n    echo \"${YELLOW}⚠️  Please edit backend/.env with your database credentials${NC}\"\nfi\necho \"Installing npm packages...\"\nnpm install\necho \"${GREEN}✅ Backend setup complete${NC}\"\ncd ..\n\n# Setup Frontend\necho \"\"\necho \"${YELLOW}[6/7] Installing Frontend dependencies...${NC}\"\ncd frontend\nif [ ! -f \".env\" ]; then\n    echo \"Creating .env file from template...\"\n    cp .env.example .env\nfi\necho \"Installing npm packages...\"\nnpm install\necho \"${GREEN}✅ Frontend setup complete${NC}\"\ncd ..\n\n# Setup Database\necho \"\"\necho \"${YELLOW}[7/7] Setting up Database...${NC}\"\necho \"${YELLOW}Please enter your MySQL root password:${NC}\"\nread -s DB_PASSWORD\nmysql -u root -p${DB_PASSWORD} << EOF\nCREATE DATABASE IF NOT EXISTS barcode_system;\nUSE barcode_system;\nSOURCE database/schema.sql;\nEOF\n\nif [ $? -eq 0 ]; then\n    echo \"${GREEN}✅ Database created successfully${NC}\"\nelse\n    echo \"${RED}❌ Database creation failed. Please check your MySQL password.${NC}\"\n    exit 1\nfi\n\necho \"\"\necho \"═══════════════════════════════════════════════════════════\"\necho \"${GREEN}✅ Installation Complete!${NC}\"\necho \"═══════════════════════════════════════════════════════════\"\necho \"\"\necho \"${YELLOW}📋 Next Steps:${NC}\"\necho \"\"\necho \"1. ${YELLOW}Edit configuration files:${NC}\"\necho \"   nano backend/.env    # Add your database credentials\"\necho \"\"\necho \"2. ${YELLOW}Start Backend (Terminal 1):${NC}\"\necho \"   cd backend\"\necho \"   npm start\"\necho \"   Server will run on: http://localhost:5000\"\necho \"\"\necho \"3. ${YELLOW}Start Frontend (Terminal 2):${NC}\"\necho \"   cd frontend\"\necho \"   npm start\"\necho \"   Application will open at: http://localhost:3000\"\necho \"\"\necho \"${GREEN}🎉 Your application is ready to use!${NC}\"\necho \"\"\necho \"📚 Documentation:\"\necho \"   - Setup Guide: docs/SETUP.md\"\necho \"   - API Docs: docs/API.md\"\necho \"   - Architecture: docs/ARCHITECTURE.md\"\necho \"\"\n"
